using System;

[AttributeUsage(AttributeTargets.All)]
public class ParamAttr : Attribute
{
    public ParamAttr(string description) { Description = description; }
    public string Description { get; }
}

public interface IProductService
{
    string GetProduct([ParamAttr("product id")] int id, string name);
}

[YS.Knife.ExposeApi(typeof(IProductService), ParameterAttributePatterns = new string[] { "ParamAttr" })]
public class TestController
{
}

