#pragma warning disable CS1591, CS1573
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
namespace 
{
    [ApiController]
    [Route("api/[controller]")]
    public class ProductController : ControllerBase
    {
        private readonly global::IProductService iProductService;
        public ProductController(global::IProductService iProductService)
        {
            this.iProductService = iProductService;
        }

        [Route("GetProduct/{id}")]
        [HttpGet]
        public string GetProduct([FromRoute] [global::ParamAttr("product id")] int id, [FromQuery] string name)
        {
            return this.iProductService.GetProduct(id, name);                    
        }
    }
}
